#!/usr/bin/env bash
# =====================================================================================
# Schedule Forensics — one-file installer (Tier 1 - 16 GB RAM, no discrete GPU) — Linux
# =====================================================================================
# Generated by tools/installer/build_installers.py — DO NOT hand-edit below the CONFIG
# block; regenerate instead. Bash 4+; needs: python3 (3.11+), curl (only if installing
# Ollama), base64.
#
# What this does (checking before installing — nothing already present is reinstalled):
#   1. Verifies machine fit (RAM / GPU) for this tier — warns, never blocks.
#   2. Verifies Python 3.11+ (tells you the distro package to install if missing).
#   3. Installs the tool into its OWN venv from the wheel EMBEDDED in this file
#      (no internet needed for the tool itself).
#   4. Optionally installs Ollama + this tier's local AI model (skippable — the tool
#      runs fully without AI).
#   5. Creates Start/Stop launchers (~/.local/bin + desktop entries), an uninstaller,
#      and a first-run README.
#
# DATA SOVEREIGNTY: the installed tool binds 127.0.0.1 only — schedule data never
# leaves the machine. Internet is used ONLY at install time for public prerequisites.
#
# Run:            bash install-tier1.sh
# Non-interactive smoke test (skips AI, temp root):  SF_INSTALLER_SMOKE=1 bash install-tier1.sh
# =====================================================================================

# ------------------------------- TIER CONFIG (edit freely) --------------------------
# Defaults chosen 2026-07-02 per INSTALLER-SPEC.md SS3 (operator authorized autonomous build;
# edit these five lines freely - they are the ONLY tier-specific values in this file).
TIER_LABEL="Tier 1 - 16 GB RAM, no discrete GPU"
MIN_RAM_GB=16
NEEDS_GPU=false
OLLAMA_MODEL="llama3.2:3b"
MODEL_DISK_GB=2
# ---------------------------- END TIER CONFIG — SHARED BODY -------------------------

set -euo pipefail
SMOKE="${SF_INSTALLER_SMOKE:-0}"
if [ "$SMOKE" = "1" ]; then
  INSTALL_ROOT="${SF_INSTALL_ROOT:-$(mktemp -d)/ScheduleForensics}"
else
  INSTALL_ROOT="${SF_INSTALL_ROOT:-$HOME/.local/share/ScheduleForensics}"
fi
VENV_DIR="$INSTALL_ROOT/venv"
APP_PORT=8321
mkdir -p "$INSTALL_ROOT"

step() { printf '\n\033[36m==> %s\033[0m\n' "$1"; }
ok()   { printf '    \033[32m[ok]\033[0m %s\n' "$1"; }
warn() { printf '    \033[33m[!!]\033[0m %s\n' "$1"; }

echo ""
echo "Schedule Forensics installer — ${TIER_LABEL}"
echo "Install location: $INSTALL_ROOT"

# --- 1. machine fit (warn-only) ------------------------------------------------------
step "Checking machine fit for this tier"
ram_gb=$(( $(grep MemTotal /proc/meminfo | awk '{print $2}') / 1024 / 1024 ))
if [ "$ram_gb" -lt "$MIN_RAM_GB" ]; then
  warn "This machine reports ${ram_gb} GB RAM; this tier targets ${MIN_RAM_GB} GB+. The tool will run; the AI model may be slow or fail to load."
else
  ok "${ram_gb} GB RAM (tier targets ${MIN_RAM_GB} GB+)"
fi
if [ "$NEEDS_GPU" = "true" ]; then
  if command -v nvidia-smi >/dev/null 2>&1 || ls /dev/dri/render* >/dev/null 2>&1; then
    ok "GPU device detected"
  else
    warn "No GPU detected; this tier's AI model expects one (it will run on CPU — slow — or fail to load)."
  fi
fi

# --- 2. Python 3.11+ ------------------------------------------------------------------
step "Checking Python 3.11+"
PY=""
for cand in python3.13 python3.12 python3.11 python3; do
  if command -v "$cand" >/dev/null 2>&1; then
    if "$cand" -c 'import sys; raise SystemExit(0 if sys.version_info >= (3, 11) else 1)'; then
      PY="$cand"; break
    fi
  fi
done
if [ -z "$PY" ]; then
  echo "Python 3.11+ not found. Install it with your package manager, e.g.:" >&2
  echo "    sudo apt install python3.12 python3.12-venv     # Debian/Ubuntu" >&2
  echo "    sudo dnf install python3.12                     # Fedora" >&2
  exit 1
fi
ok "Python found: $PY ($($PY -V))"

# --- 3. the tool, into its own venv, from the wheel embedded below --------------------
step "Installing Schedule Forensics into its own environment"
if [ ! -x "$VENV_DIR/bin/python" ]; then
  "$PY" -m venv "$VENV_DIR"
  ok "Created venv"
else
  ok "venv already present (re-using)"
fi
WHEEL_PATH="$INSTALL_ROOT/schedule_forensics-1.0.82-py3-none-any.whl"
# the payload sits between the PAYLOAD markers at the end of this file
awk '/^# ===BEGIN WHEEL_B64===/{flag=1; next} /^# ===END WHEEL_B64===/{flag=0} flag {sub(/^# ?/, ""); print}' "$0" | base64 -d > "$WHEEL_PATH"
"$VENV_DIR/bin/python" -m pip install --quiet --upgrade pip
"$VENV_DIR/bin/python" -m pip install --quiet --force-reinstall "$WHEEL_PATH"
"$VENV_DIR/bin/python" -c "import schedule_forensics" || { echo "The tool failed to import after install." >&2; exit 1; }
ok "Installed schedule_forensics-1.0.82-py3-none-any.whl"
# optional HUD telemetry enhancer — best-effort, never fatal (stdlib collectors cover Linux)
"$VENV_DIR/bin/python" -m pip install --quiet psutil >/dev/null 2>&1 || true

# --- 3b. vendored MPXJ converter (native .mpp support) --------------------------------
# The wheel is pure Python; the Java converter (tools/mpxj) rides in the repository next
# to this installer and is copied beside the venv, where the runtime's walk-up discovery
# finds it automatically (ADR-0193). Without it every .mpp import fails.
REPO_MPXJ="$(cd "$(dirname "$0")/.." 2>/dev/null && pwd)/tools/mpxj"
if [ -f "$REPO_MPXJ/classes/MpxjToMspdi.class" ]; then
  mkdir -p "$INSTALL_ROOT/tools"
  rm -rf "$INSTALL_ROOT/tools/mpxj"
  cp -R "$REPO_MPXJ" "$INSTALL_ROOT/tools/mpxj"
  ok "MPXJ converter deployed (native .mpp import enabled)"
else
  warn "tools/mpxj not found next to this installer — native .mpp import stays OFF"
  warn "  (run the installer from the repository checkout, or set SF_MPXJ_HOME)"
fi

# --- 4. Ollama + this tier's local AI model -------------------------------------------
step "Local AI ($OLLAMA_MODEL) — the tool runs fully without it (skippable)"
if [ "$SMOKE" = "1" ]; then
  warn "Smoke mode: skipping AI install"
else
  read -r -p "    Install Ollama + pull '$OLLAMA_MODEL' (~${MODEL_DISK_GB} GB download)? [Y/n] " ans || ans="n"
  if [[ ! "$ans" =~ ^[Nn] ]]; then
    if ! command -v ollama >/dev/null 2>&1; then
      curl -fsSL https://ollama.com/install.sh | sh
      ok "Ollama installed"
    else
      ok "Ollama already present"
    fi
    echo "    Pulling $OLLAMA_MODEL (this is the big download)..."
    ollama pull "$OLLAMA_MODEL"
    ok "Model ready: $OLLAMA_MODEL"
  else
    warn "Skipped — the tool works fully offline; AI prose stays off until a model is installed"
  fi
fi

# --- 5. Start / Stop launchers, desktop entries, uninstaller, README ------------------
step "Creating Start/Stop launchers, uninstaller, and first-run README"
START_SH="$INSTALL_ROOT/start-schedule-forensics.sh"
cat > "$START_SH" <<EOF
#!/usr/bin/env bash
# Schedule Forensics — start (loopback-only; the browser opens automatically).
exec "$VENV_DIR/bin/python" -c "from schedule_forensics.launcher import main; main(port=$APP_PORT)"
EOF
chmod +x "$START_SH"

STOP_SH="$INSTALL_ROOT/stop-schedule-forensics.sh"
cat > "$STOP_SH" <<EOF
#!/usr/bin/env bash
# Schedule Forensics — graceful stop (asks the local app to shut itself down).
if command -v curl >/dev/null 2>&1; then
  curl -fsS -X POST "http://127.0.0.1:$APP_PORT/api/shutdown" >/dev/null 2>&1 \\
    && echo "Schedule Forensics stopped." || echo "Not running (or already stopped)."
else
  "$VENV_DIR/bin/python" - <<'PY'
import urllib.request
try:
    urllib.request.urlopen(urllib.request.Request(
        "http://127.0.0.1:$APP_PORT/api/shutdown", method="POST"), timeout=5)
    print("Schedule Forensics stopped.")
except Exception:
    print("Not running (or already stopped).")
PY
fi
EOF
chmod +x "$STOP_SH"

UNINST="$INSTALL_ROOT/uninstall-schedule-forensics.sh"
cat > "$UNINST" <<EOF
#!/usr/bin/env bash
# Uninstall Schedule Forensics: removes the app folder, launchers, desktop entries.
# Leaves Python / Ollama in place (shared programs); remove the AI model with:
#     ollama rm $OLLAMA_MODEL
"$STOP_SH" || true
rm -f "\$HOME/.local/bin/schedule-forensics-start" "\$HOME/.local/bin/schedule-forensics-stop"
rm -f "\$HOME/.local/share/applications/schedule-forensics-start.desktop" \\
      "\$HOME/.local/share/applications/schedule-forensics-stop.desktop"
rm -rf "$INSTALL_ROOT"
echo "Schedule Forensics removed."
EOF
chmod +x "$UNINST"

cat > "$INSTALL_ROOT/FIRST-RUN-README.txt" <<EOF
Schedule Forensics — first run
==============================
Start:  run "Start Schedule Forensics" from your app menu (or $START_SH).
        Your browser opens http://127.0.0.1:$APP_PORT — everything runs ON THIS MACHINE.
Stop:   "Stop Schedule Forensics" (closing the browser also stops it after an idle delay).
Data:   your schedule files NEVER leave this computer (loopback-only by design).
AI:     enable it in AI Settings inside the app (model: $OLLAMA_MODEL).
Remove: $UNINST
EOF

if [ "$SMOKE" != "1" ]; then
  mkdir -p "$HOME/.local/bin" "$HOME/.local/share/applications"
  ln -sf "$START_SH" "$HOME/.local/bin/schedule-forensics-start"
  ln -sf "$STOP_SH"  "$HOME/.local/bin/schedule-forensics-stop"
  cat > "$HOME/.local/share/applications/schedule-forensics-start.desktop" <<EOF
[Desktop Entry]
Type=Application
Name=Start Schedule Forensics
Exec=$START_SH
Terminal=false
Categories=Office;
EOF
  cat > "$HOME/.local/share/applications/schedule-forensics-stop.desktop" <<EOF
[Desktop Entry]
Type=Application
Name=Stop Schedule Forensics
Exec=$STOP_SH
Terminal=false
Categories=Office;
EOF
  ok "Launchers in ~/.local/bin + app-menu entries; uninstaller + README in $INSTALL_ROOT"
else
  ok "Smoke mode: launchers written to $INSTALL_ROOT only (no menu entries)"
fi

echo ""
printf '\033[32mDONE — run "schedule-forensics-start" (or the app-menu entry) to begin.\033[0m\n'
echo "(Everything runs locally at http://127.0.0.1:$APP_PORT — no data leaves this machine.)"
exit 0

